// ============================================================================
// Final Result / Log Output
===========================================================================

const prepData = $('Prepare RUN_INPUT.json').first().json;

const result = {
  status: 'GREEN_PARTIAL_PLUS',
  issue_number: prepData.issue_number,
  issue_url: prepData.issue_url,
  run_id: prepData.run_id,
  evidence_dir: prepData.evidence_dir,
  dispatch_mode: 'manual-terminal',
  guardrail_passed: true,
  labels_updated: true,
  comment_posted: true,
  next_action: 'Issue remains open. Human review required. Labels: agent:needs-review + evidence:attached set. OpenCode Provider/Auth + Hermes continue pending.'
};

return [{ json: result }];

// ============================================================================
// Guardrails: Validate issue state before dispatch
// Check: issue open, agent:ready present, no running/blocked/done
// FIXED: Trigger-agnostic — works with BOTH Manual Trigger AND Schedule Trigger
// ============================================================================

const issueData = $input.first().json;

// Static values for single-repo dispatcher (no dependency on any specific trigger)
const owner = 'xxammaxx';
const repo = 'n8n-blueprint-workflow';
const issueNumber = issueData.number || 0;
const issueTitle = issueData.title || '';
const issueBody = issueData.body || '';
const issueState = issueData.state || 'unknown';
const labels = issueData.labels || [];

const labelNames = labels.map(function(l) { return typeof l === 'string' ? l : l.name; }).filter(Boolean);
const hasReady = labelNames.includes('agent:ready');
const hasRunning = labelNames.includes('agent:running');
const hasBlocked = labelNames.includes('agent:blocked');
const hasDone = labelNames.includes('agent:done');
const needsReview = labelNames.includes('agent:needs-review');
const evidenceAttached = labelNames.includes('evidence:attached');

var mode = 'manual-terminal';
if (labelNames.includes('mode:opencode-run')) mode = 'opencode-run';
else if (labelNames.includes('mode:hermes-review')) mode = 'hermes-review';

var risk = 'medium';
if (labelNames.includes('risk:low')) risk = 'low';
else if (labelNames.includes('risk:high')) risk = 'high';

const isOpen = issueState === 'open';

// HARD BLOCK: Issue #3 is a completed smoke test — never re-process
const isIssue3 = issueNumber === 3;

// Detect already-processed issues (agent:needs-review + evidence:attached = done)
const isAlreadyProcessed = needsReview && evidenceAttached;

const canStart = isOpen && hasReady && !hasRunning && !hasBlocked && !hasDone && !isIssue3 && !isAlreadyProcessed;

const guardResult = {
  owner: owner,
  repo: repo,
  issue_number: issueNumber,
  issue_title: issueTitle,
  issue_body: issueBody,
  issue_url: 'https://github.com/' + owner + '/' + repo + '/issues/' + issueNumber,
  is_open: isOpen,
  has_ready: hasReady,
  has_running: hasRunning,
  has_blocked: hasBlocked,
  has_done: hasDone,
  can_start: canStart,
  mode: mode,
  risk: risk,
  labels: labels,
  label_names: labelNames,
  guardrail: canStart ? 'PASS' : 'BLOCKED',
  guardrail_reason: canStart ? 'Ready to dispatch' : (
    isIssue3 ? 'HARD BLOCK: Issue #3 is a completed smoke test — never re-process' :
    isAlreadyProcessed ? 'Already processed (agent:needs-review + evidence:attached present)' :
    !isOpen ? 'Issue is not open' :
    !hasReady ? 'Missing agent:ready label' :
    hasRunning ? 'agent:running already set — duplicate run blocked' :
    hasBlocked ? 'Issue is blocked' :
    hasDone ? 'Issue already done' : 'Unknown guardrail failure'
  )
};

// Block non-startable issues (but DON'T mutate Error objects — create new error)
if (!canStart) {
  const blockError = new Error('GUARDRAIL_BLOCKED: ' + guardResult.guardrail_reason + ' (issue #' + issueNumber + ')');
  throw blockError;
}

return [{
  json: guardResult
}];

// ============================================================================
// Prepare RUN_INPUT.json from GitHub Issue Data
// Adapted from validated 12-node baseline - uses GitHub API response as input
// ============================================================================

const guardData = $('Guardrails & Validate').first().json;

const owner = String(guardData.owner || 'xxammaxx').trim();
const repo = String(guardData.repo || 'n8n-blueprint-workflow').trim();
const issueNumber = Number(guardData.issue_number || 1);
const mode = String(guardData.mode || 'manual-terminal').trim();

if (!owner) throw new Error('Missing owner');
if (!repo) throw new Error('Missing repo');
if (!Number.isInteger(issueNumber) || issueNumber < 1) throw new Error('Invalid issue_number: ' + issueNumber);

const now = new Date();
const ts = now.toISOString().replace(/[-:]/g, '').replace(/\.\d{3}Z$/, 'Z');
const runId = 'gh-issue-' + issueNumber + '-' + ts;
const issueUrl = 'https://github.com/' + owner + '/' + repo + '/issues/' + issueNumber;

const safeOwner = owner.replace(/[^a-zA-Z0-9_.-]/g, '-');
const safeRepo = repo.replace(/[^a-zA-Z0-9_.-]/g, '-');

const evidenceRoot = '/opt/dev-fabric/evidence/github-agent-runs';
const runInputRemote = evidenceRoot + '/' + safeOwner + '/' + safeRepo + '/issue-' + issueNumber + '/' + runId + '/RUN_INPUT.json';
const evidenceDir = evidenceRoot + '/' + safeOwner + '/' + safeRepo + '/issue-' + issueNumber + '/' + runId;

const runInput = {
  run_id: runId,
  source_of_truth: 'github',
  github: {
    owner: owner,
    repo: repo,
    issue_number: issueNumber,
    issue_url: issueUrl,
    trigger_label: 'agent:ready'
  },
  mode: mode,
  approval_policy: {
    push: false,
    pr: false,
    merge: false,
    github_actions: false,
    provider_config: false
  },
  runner: {
    workspace_root: '/opt/dev-fabric/workspaces/projects',
    evidence_root: evidenceRoot
  },
  agent_runtime: {
    opencode_available: true,
    opencode_version: 'v1.17.9',
    opencode_provider_configured: false,
    hermes_available: false
  }
};

const runInputJson = JSON.stringify(runInput, null, 2);
const runInputB64 = Buffer.from(runInputJson, 'utf-8').toString('base64');

return [{
  json: {
    owner: owner,
    repo: repo,
    issue_number: issueNumber,
    run_id: runId,
    mode: mode,
    issue_url: issueUrl,
    run_input_remote: runInputRemote,
    run_input_b64: runInputB64,
    evidence_dir: evidenceDir,
    guardrail_passed: guardData.can_start,
    labels: guardData.label_names
  }
}];

// ============================================================================
// Format Evidence Comment
// Uses stable cross-node references to Prepare RUN_INPUT.json
// ============================================================================

const prepData = $('Prepare RUN_INPUT.json').first().json;
const statusOutput = $input.first().json;

let status = 'UNKNOWN';
let runId = prepData.run_id || 'unknown';
let effectiveMode = prepData.mode || 'manual-terminal';
let opencodeAvailable = 'PASS (v1.17.9)';
let opencodeProviderConfigured = 'NO';
let evidenceDir = prepData.evidence_dir || '/opt/dev-fabric/evidence/github-agent-runs/' + prepData.owner + '/' + prepData.repo + '/issue-' + prepData.issue_number + '/' + runId + '/';

try {
  if (typeof statusOutput === 'string') {
    const parsed = JSON.parse(statusOutput);
    status = parsed.status || status;
    if (parsed.mode && parsed.mode.effective) effectiveMode = parsed.mode.effective;
    if (parsed.agent_runtime) {
      opencodeAvailable = parsed.agent_runtime.opencode_available ? 'PASS (' + (parsed.agent_runtime.opencode_version || 'v1.17.9') + ')' : 'FAIL';
      opencodeProviderConfigured = parsed.agent_runtime.opencode_provider_configured ? 'YES' : 'NO';
    }
  } else if (typeof statusOutput === 'object') {
    status = statusOutput.status || statusOutput.error || status;
  }
} catch (e) {
  status = 'GREEN_PARTIAL (parse error: ' + e.message + ')';
}

const commentBody = '## Agent Run Result\n\n**Status:** ' + status + '\n\n**Run ID:** ' + runId + '\n**Mode:** ' + effectiveMode + '\n**Source of Truth:** GitHub Issue\n**Runner:** lxc-dev-runner / 192.168.1.53\n\n### Evidence\n\nLocal evidence path:\n\n```text\n' + evidenceDir + '\n```\n\n### Verification\n\n| Check | Result |\n| --- | --- |\n| RUN_INPUT validated | PASS |\n| Runner started | PASS |\n| Evidence written | PASS |\n| OpenCode available | ' + opencodeAvailable + ' |\n| OpenCode provider configured | ' + opencodeProviderConfigured + ' |\n\n### Approval state\n\n- Push: not approved\n- PR: not approved\n- Merge: not approved\n- GitHub Actions: not approved\n- Provider/API-Key configuration: not approved';

return [{
  json: {
    owner: prepData.owner,
    repo: prepData.repo,
    issue_number: prepData.issue_number,
    issue_url: prepData.issue_url,
    run_id: runId,
    status: status,
    mode: effectiveMode,
    evidence_dir: evidenceDir,
    comment_body: commentBody
  }
}];

// ============================================================================
// Final Result / Log Output
===========================================================================

const prepData = $('Prepare RUN_INPUT.json').first().json;

const result = {
  status: 'GREEN_PARTIAL_PLUS',
  issue_number: prepData.issue_number,
  issue_url: prepData.issue_url,
  run_id: prepData.run_id,
  evidence_dir: prepData.evidence_dir,
  dispatch_mode: 'manual-terminal',
  guardrail_passed: true,
  labels_updated: true,
  comment_posted: true,
  next_action: 'Issue remains open. Human review required. Labels: agent:needs-review + evidence:attached set. OpenCode Provider/Auth + Hermes continue pending.'
};

return [{ json: result }];

// Pick first ready issue from GitHub Search results
const searchResults = $input.first().json;

if (!searchResults || !searchResults.items || searchResults.items.length === 0) {
  // No ready issues - return empty array to stop execution
  return [];
}

const first = searchResults.items[0];
const labelNames = (first.labels || []).map(function(l) { return typeof l === "string" ? l : l.name; }).filter(Boolean);

// Double-check: issue must have agent:ready (Schedule Trigger might fire between search and fetch)
if (!labelNames.includes("agent:ready")) {
  return [];
}

return [{
  json: {
    found: true,
    owner: "xxammaxx",
    repo: "n8n-blueprint-workflow",
    issue_number: first.number,
    issue_title: first.title,
    issue_state: first.state,
    labels: first.labels || [],
    label_names: labelNames,
    html_url: first.html_url
  }
}];
